CREATE INDEX IF NOT EXISTS idx_transfer_date ON "transfer"(transfer_date);                  -- Transfers that happened within a specific date range
CREATE INDEX IF NOT EXISTS idx_transfer_player ON "transfer"(player_id);                    -- Transfers made by a specific player
